using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.FileProviders;
using System;
using System.IO;
using System.Threading.Tasks;

namespace AvatarUploader
{
    public class Startup
    {
        public void Configure(IApplicationBuilder app, IWebHostEnvironment env)
        {
            app.UseRouting();
            app.UseEndpoints(endpoints =>
            {
                endpoints.MapPost("/upload", UploadFile);
            });
        }
    }

    public class Program
    {
        public static void Main(string[] args)
        {
            var builder = WebApplication.CreateBuilder(args);

            // Add services to the container.
            builder.Services.AddControllersWithViews();

            var app = builder.Build();

            // Configure the HTTP Request Pipeline.
            if (!app.Environment.IsDevelopment())
            {
                app.UseExceptionHandler("/Home/Error");
                // The default HSTS value is 30 days. You may want to change this for production scenarios, see https://aka.ms/aspnetcore-hsts.
                app.UseHsts();
            }

            app.UseHttpsRedirection();
            app.UseStaticFiles();

            app.UseRouting();

            app.UseAuthorization();

            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllerRoute(
                    name: "default",
                    pattern: "{controller=Home}/{action=Index}/{id?}");
            });

            app.Run();
        }
    }

    public class AvatarUploaderController : Controller
    {
        private readonly IWebHostEnvironment _env;

        public AvatarUploaderController(IWebHostEnvironment env)
        {
            _env = env;
        }

        [HttpPost]
        public async Task<IActionResult> UploadFile()
        {
            var files = Request.Form.Files;
            if (files.Count == 0) return BadRequest("No file uploaded");

            foreach (var file in files)
            {
                if (!IsAllowedFileType(file.FileName))
                    return BadRequest($"Invalid file type: {file.FileName}");

                var filePath = Path.Combine(_env.WebRootPath, "uploads", Guid.NewGuid().ToString() + Path.GetExtension(file.FileName));
                using (var stream = new FileStream(filePath, FileMode.CreateNew))
                {
                    await file.CopyToAsync(stream);
                }
            }

            return Ok($"File uploaded successfully. File path: {filePath}");
        }

        private bool IsAllowedFileType(string fileName)
        {
            var allowedTypes = new[] { ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".docx", ".xlsx", ".pptx" };
            foreach (var type in allowedTypes)
                if (fileName.EndsWith(type, StringComparison.OrdinalIgnoreCase))
                    return true;
            return false;
        }
    }
